#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, m;
int fa[5005];
int id;
double ans;
struct node
{
	double val;
	int id;
} q[8000005];
struct xy
{
	int x, y;
	int id;
} a[5005];
bool cmp1(xy aa, xy bb)
{
	return aa.y + aa.x < bb.y + bb.x;
}
bool cmp2(xy aa, xy bb)
{
	return aa.x < bb.x;
}
bool cmp3(xy aa, xy bb)
{
	return aa.y < bb.y;
}
bool cmp4(const node& aa, const node& bb)
{
	return aa.val < bb.val;
}
int find(int x)
{
	return fa[x] == x ? x : fa[x] = find(fa[x]);
}
signed main(void)
{
	n = read();
	for (int i = 1; i <= n; ++i)
	{
		fa[i] = i;
	}
	for (int i = 1; i <= n; ++i)
	{
		a[i].x = read(), a[i].y = read(), a[i].id = i;
	}
	sort(a + 1, a + n + 1, cmp1);
	for (int i = 1; i <= n; ++i)
	{
		for (int j = i + 1; j <= min(n, i + 500); ++j)
		{
			int id1 = a[i].id, id2 = a[j].id;
			q[++id] = {sqrt((double)(a[i].x - a[j].x) * (a[i].x - a[j].x) + (double)(a[i].y - a[j].y) * (a[i].y - a[j].y)), id1 * 400000 + id2};
		}
	}
	sort(a + 1, a + n + 1, cmp2);
	for (int i = 1; i <= n; ++i)
	{
		for (int j = i + 1; j <= min(n, i + 500); ++j)
		{
			int id1 = a[i].id, id2 = a[j].id;
			q[++id] = {sqrt((double)(a[i].x - a[j].x) * (a[i].x - a[j].x) + (double)(a[i].y - a[j].y) * (a[i].y - a[j].y)), id1 * 400000 + id2};
		}
	}
	sort(a + 1, a + n + 1, cmp3);
	for (int i = 1; i <= n; ++i)
	{
		for (int j = i + 1; j <= min(n, i + 500); ++j)
		{
			int id1 = a[i].id, id2 = a[j].id;
			q[++id] = {sqrt((double)(a[i].x - a[j].x) * (a[i].x - a[j].x) + (double)(a[i].y - a[j].y) * (a[i].y - a[j].y)), id1 * 400000 + id2};
		}
	}
	sort(q + 1, q + id + 1, cmp4);
	for (int i = 1; i <= id; ++i)
	{
		double val = q[i].val;
		int v = q[i].id / 400000, u = q[i].id % 400000;
		if ((v = find(v)) == (u = find(u))) continue;
		fa[v] = u, ans += val;
	}
	printf("%.2f", ans);
	return false;
}
